import "single_sig.ark";

options {
  server = server;
  exit = exit;
}

contract InventoryHedge(
  pubkey  claimPk,
  pubkey  longPk,
  pubkey  oraclePk,
  bytes32 ticker,
  int     targetFiat,
  int     totalCollateral,
  int     fundingRatePerSec,
  int     lastUpdate,
  int     collateralRatioPct,
  int     exit
) {

  function transfer(signature claimSig, pubkey newClaimPk) {
    require(checkSig(claimSig, claimPk), "invalid claim sig");

    require(
      tx.outputs[0].scriptPubKey == new InventoryHedge(
        newClaimPk, longPk, oraclePk, ticker,
        targetFiat, totalCollateral, fundingRatePerSec, lastUpdate,
        collateralRatioPct, exit
      ),
      "invalid transfer output"
    );
    require(tx.outputs[0].value >= totalCollateral, "collateral not preserved");
  }

  function updateFunding(signature longSig, int newFundingRatePerSec) {
    require(checkSig(longSig, longPk), "invalid long-leg sig");
    require(newFundingRatePerSec >= 0, "negative funding rate disallowed");

    int elapsed           = tx.offchainTime - lastUpdate;
    require(elapsed >= 0, "clock regression");
    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;
    int delta             = targetFiat * rateElapsedScaled / 1000000;
    int newTargetFiat     = targetFiat + delta;
    require(newTargetFiat > 0, "claim wiped by funding");

    if (fundingRatePerSec != 0) {
      require(delta > 0, "no accrual; wait longer");
    }

    require(
      tx.outputs[0].scriptPubKey == new InventoryHedge(
        claimPk, longPk, oraclePk, ticker,
        newTargetFiat, totalCollateral, newFundingRatePerSec, tx.offchainTime,
        collateralRatioPct, exit
      ),
      "invalid update output"
    );
    require(tx.outputs[0].value >= totalCollateral, "collateral not preserved");
  }

  function addCapital(signature longSig, int amount) {
    require(checkSig(longSig, longPk), "invalid long-leg sig");
    require(amount > 0, "zero amount");

    int newTotalCollateral = totalCollateral + amount;

    require(
      tx.outputs[0].scriptPubKey == new InventoryHedge(
        claimPk, longPk, oraclePk, ticker,
        targetFiat, newTotalCollateral, fundingRatePerSec, lastUpdate,
        collateralRatioPct, exit
      ),
      "invalid output"
    );
    require(tx.outputs[0].value >= newTotalCollateral, "collateral not deposited");
  }

  function removeCapital(
    signature longSig,
    int       amount,
    int       oraclePrice,
    int       oracleTime,
    signature oracleSig
  ) {
    require(checkSig(longSig, longPk), "invalid long-leg sig");
    require(amount > 0, "zero amount");
    require(oraclePrice > 0, "invalid oracle price");

    int oracleAge = tx.offchainTime - oracleTime;
    require(oracleAge >= 0, "future-dated oracle");
    require(oracleAge <= 600, "stale oracle");

    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);
    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), "invalid oracle signature");

    int elapsed            = tx.offchainTime - lastUpdate;
    require(elapsed >= 0, "clock regression");
    int rateElapsedScaled  = fundingRatePerSec * elapsed / 1000000;
    int delta              = targetFiat * rateElapsedScaled / 1000000;
    int newTargetFiat      = targetFiat + delta;
    int currentClaimBase   = newTargetFiat * 100000000 / oraclePrice;
    int minCollateral      = currentClaimBase * (100 + collateralRatioPct) / 100;
    int newTotalCollateral = totalCollateral - amount;
    require(newTotalCollateral >= minCollateral, "would breach collateral ratio");

    require(
      tx.outputs[0].scriptPubKey == new InventoryHedge(
        claimPk, longPk, oraclePk, ticker,
        targetFiat, newTotalCollateral, fundingRatePerSec, lastUpdate,
        collateralRatioPct, exit
      ),
      "invalid vault output"
    );
    require(tx.outputs[0].value >= newTotalCollateral, "vault underfunded");
    require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), "output 1 not long leg");
    require(tx.outputs[1].value >= amount, "long leg underpaid");
  }

  function claimExit(
    signature claimSig,
    int       oraclePrice,
    int       oracleTime,
    signature oracleSig
  ) {
    require(checkSig(claimSig, claimPk), "invalid claim sig");
    require(oraclePrice > 0, "invalid oracle price");

    int oracleAge = tx.offchainTime - oracleTime;
    require(oracleAge >= 0, "future-dated oracle");
    require(oracleAge <= 600, "stale oracle");

    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);
    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), "invalid oracle signature");

    int elapsed           = tx.offchainTime - lastUpdate;
    require(elapsed >= 0, "clock regression");
    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;
    int delta             = targetFiat * rateElapsedScaled / 1000000;
    int newTargetFiat     = targetFiat + delta;
    int claimRaw          = newTargetFiat * 100000000 / oraclePrice;

    if (claimRaw <= 0) {
      require(tx.outputs[0].value >= totalCollateral, "long leg underpaid");
      require(tx.outputs[0].scriptPubKey == new SingleSig(longPk), "output 0 not long leg");
    } else {
      if (claimRaw >= totalCollateral) {
        require(tx.outputs[0].value >= totalCollateral, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
      } else {
        require(tx.outputs[0].value >= claimRaw, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
        int longPayout = totalCollateral - claimRaw;
        if (longPayout > 330) {
          require(tx.outputs[1].value >= longPayout, "long leg underpaid");
          require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), "output 1 not long leg");
        }
      }
    }
  }

  function longExit(
    signature longSig,
    int       oraclePrice,
    int       oracleTime,
    signature oracleSig
  ) {
    require(checkSig(longSig, longPk), "invalid long-leg sig");
    require(oraclePrice > 0, "invalid oracle price");

    int oracleAge = tx.offchainTime - oracleTime;
    require(oracleAge >= 0, "future-dated oracle");
    require(oracleAge <= 600, "stale oracle");

    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);
    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), "invalid oracle signature");

    int elapsed           = tx.offchainTime - lastUpdate;
    require(elapsed >= 0, "clock regression");
    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;
    int delta             = targetFiat * rateElapsedScaled / 1000000;
    int newTargetFiat     = targetFiat + delta;
    int claimRaw          = newTargetFiat * 100000000 / oraclePrice;

    if (claimRaw <= 0) {
      require(tx.outputs[0].value >= totalCollateral, "long leg underpaid");
      require(tx.outputs[0].scriptPubKey == new SingleSig(longPk), "output 0 not long leg");
    } else {
      if (claimRaw >= totalCollateral) {
        require(tx.outputs[0].value >= totalCollateral, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
      } else {
        require(tx.outputs[0].value >= claimRaw, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
        int longPayout = totalCollateral - claimRaw;
        if (longPayout > 330) {
          require(tx.outputs[1].value >= longPayout, "long leg underpaid");
          require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), "output 1 not long leg");
        }
      }
    }
  }
}
